let SearchComponent = () => {

    let onChangeInput = (e) => {
        console.log("onChangeInput"+e.currentTarget.value)
    }

    let clickSearch = () => {
        fetch("")
    }


    return (
        <div className="search-form">
            <h2>Encuentra una revista participante</h2>
            <input type="text" className="search-input" placeholder="issn" onChange={onChangeInput}/>
            <button className="search-button" onClick={clickSearch}>Search</button>
        </div>
    )
}

export default SearchComponent;
